class Solution:
    def minSubarray(self, nums, p):
        n = len(nums)
        total = sum(nums) % p
        if total == 0:
            return 0
        best = -1
        for i in range(n):
            s = 0
            for j in range(i, n):
                s = (s + nums[j]) % p
                length = j - i + 1
                if length == n:
                    continue
                if s == total:
                    if best == -1 or length < best:
                        best = length
        return best

