class Solution:
    def minSubarray(self, nums, p):
        n = len(nums)
        total = sum(nums) % p
        if total == 0:
            return 0
        seen = {0: -1}
        cur = 0
        best = n
        for i, num in enumerate(nums):
            cur = (cur + num) % p
            need = (cur - total) % p
            if need in seen:
                length = i - seen[need]
                if length < best:
                    best = length
            seen[cur] = i
        return best if best < n else -1

