var minSubarray = function(nums, p) {
    const n = nums.length;
    let total = 0;
    for (const num of nums) total = (total + num) % p;
    if (total === 0) return 0;
    const seen = new Map();
    seen.set(0, -1);
    let cur = 0;
    let best = n;
    for (let i = 0; i < n; i++) {
        cur = (cur + nums[i]) % p;
        const need = ((cur - total) % p + p) % p;
        if (seen.has(need)) {
            const length = i - seen.get(need);
            if (length < best) best = length;
        }
        seen.set(cur, i);
    }
    return best < n ? best : -1;
};
